#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ull unsigned long long
const int N=505,base=131;
int n,dp[N][N],pos[N],cnt;
string s,s2;
ull has1[N],has2[N],tmp[N];
ull fun(int l,int r,int flag)
{
	if(flag==1) return has1[r]-has1[l-1]*tmp[r-l+1];
	else return has2[r]-has2[l-1]*tmp[r-l+1];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>s;
	s=" "+s+"?";
	tmp[0]=1;
	for(int i=1;i<=N-5;i++) tmp[i]=tmp[i-1]*base;
	for(int i=1;i<s.size();i++)
	{
		has1[i]=has1[i-1]*base+s[i];
		if(s[i]=='*'||s[i]=='?') pos[++cnt]=i;
	}
	cin>>n;
    int ans=0;
	while(n--)
	{
		cin>>s2;
		s2=" "+s2+" ";
		for(int i=1;i<s2.size();i++) has2[i]=has2[i-1]*base+s2[i];
		memset(dp,0,sizeof(dp));
		dp[0][0]=1;
		for(int i=0;i<cnt;i++)
		{
			if(s[pos[i]]=='*')
			{
				for(int j=1;j<s2.size();j++)
				{
					dp[i][j]|=dp[i][j-1];
				}
			}
			for(int j=0;j<s2.size();j++)
			{
				if(!dp[i][j]) continue;
				int l=pos[i]+1,r=pos[i+1]-1,l2=j+1,r2=j+r-l+1;
				if(fun(l,r,1)==fun(l2,r2,2))
				{
					if(s[pos[i+1]]=='?') dp[i+1][r2+1]=1;
					else dp[i+1][r2]=1;
				}
			}
		}
		if(!dp[cnt][s2.size()-1]) ans++;
	}
    cout<<ans;
	return 0;
}
